/*!50032 DROP TRIGGER IF EXISTS tri_student_update */;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `tri_student_update` BEFORE UPDATE ON `student` FOR EACH ROW BEGIN
    -- еҰӮжһңеҜҶз ҒеҸ‘з”ҹеҸҳеҢ–пјҢеҗҢжӯҘеҲ° sys_user
    IF NEW.password != OLD.password THEN
        UPDATE `sys_user`
        SET password = NEW.password,
            update_time = NOW()
        WHERE user_id = NEW.user_id;
    END IF;

    -- еҗҢжӯҘе…¶д»–еҹәжң¬дҝЎжҒҜ
    UPDATE `sys_user`
    SET nick_name = NEW.name,
        phonenumber = NEW.phone,
        sex = CASE NEW.gender WHEN 'з”·' THEN '0' WHEN 'еҘі' THEN '1' ELSE '0' END,
        update_time = NOW()
    WHERE user_id = NEW.user_id;
END */;;
DELIMITER ;
